[SRSReportParameterAttribute(classStr(ConDemoNoteReportContract))]
public class ConDemoNoteReportDP extends SRSReportDataProviderBase
{
    ConDemoNoteReportTmp tmpTable;
}

Method.Source:
[SRSReportDataSetAttribute(tableStr(ConDemoNoteReportTmp))]
public ConDemoNoteReportTmp getConDemoNoteReportTmp()
{
    select * from tmpTable;
    return tmpTable;
}

public void processReport()
{
    ConDemoNoteHeader noteHeader;

    delete_from tmpTable;

    insert_recordset tmpTable (NoteId, Subject)
        select NoteId, Subject
        from noteHeader;
}
